// Готовим тело запроса к резервной модели Groq (chat completions).
let transcript = '';
try { transcript = $('OpenAI Transcribe (Whisper)').item.json.text || ''; } catch (e) {}
if (!transcript) { try { transcript = $('Groq Transcribe (Fallback)').item.json.text || ''; } catch (e) {} }
if (!transcript) { throw new Error('Нет транскрипта для резервного ИИ-шага.'); }
const SYSTEM = "Ты — ассистент, который ведёт деловой дневник собственника компании. На вход ты получаешь полную расшифровку голосовой записи за день. Твоя задача — не сжать её до пары слов, а аккуратно структурировать, СОХРАНИВ всё значимое и расставив приоритеты.

Верни СТРОГО валидный JSON без markdown и без пояснений, ровно с такими полями:
{
  "Заголовок": "",
  "Главное": [],
  "Детали": [],
  "Инсайты": [],
  "Проблемы": [],
  "Следующие шаги": []
}

Правила:
- "Заголовок": одна строка (до 90 символов), суть дня; если событий несколько — 1–2 главных через «; ».
- "Главное": 2–5 ключевых пунктов — то, на чём собственник делал акцент: главные решения, события и результаты дня. Эти пункты будут выделены жирным. Формулируй содержательно, целым предложением, а не одним словом.
- "Детали": остальные значимые факты, контекст и подробности, которые прозвучали, но не являются главными. Сюда идёт всё ценное, что не попало в «Главное» — НЕ выбрасывай его.
- "Инсайты": выводы, уроки, осознания, идеи на будущее (если прозвучали).
- "Проблемы": трудности, риски, что мешает или пошло не так.
- "Следующие шаги": конкретные планируемые действия.
- Сохраняй конкретику: имена, проекты, продукты, цифры — как в записи. Пиши по-русски, по-деловому.
- Приводи названия проектов/компаний к каноническому написанию (если в расшифровке исказилось): Qirelab (qirelab.com), Urokinetic, HypeCash, Versacommerce, Granit, Raphael mission, AltaSales, Reshape, One L Professional, Jokula, Picassi, Tekom, SmartMedical, Insoftel Technologies, Metal Welding, Brandstone, «Лапа моя», Financial Suite, Pickom, ESGSyncPro, B-Sales, FinConsult, FinMan, itmouse.by; инструменты: Linear, Y Combinator, OpenAI, ChatGPT, DeepSeek.
- НИЧЕГО не выдумывай: только то, что есть в записи. Если по полю ничего нет — пустой массив []. Лучше отнести пункт в «Детали», чем потерять его.";
return { json: { model: 'llama-3.3-70b-versatile', temperature: 0.2, response_format: { type: 'json_object' }, messages: [ { role: 'system', content: SYSTEM }, { role: 'user', content: transcript } ] } };

// Собираем payload для Apps Script Web App.
// 1) Берём расшифровку и структурированное summary (тиры: Главное/Детали/...).
// 2) Считаем дату в нужной таймзоне (по умолчанию Europe/Warsaw).

const TZ = 'Europe/Warsaw'; // должна совпадать с TIMEZONE в Apps Script

const raw = $json.choices?.[0]?.message?.content ?? $json.message?.content ?? $json.content ?? $json.output ?? $json.text ?? $json;
let s;
if (typeof raw === 'string') {
  try { s = JSON.parse(raw); }
  catch (e) {
    const m = raw.match(/\{[\s\S]*\}/);
    if (!m) throw new Error('OpenAI did not return JSON: ' + raw);
    s = JSON.parse(m[0]);
  }
} else { s = raw; }

const arr = (v) => (Array.isArray(v) ? v : []);
const summary = {
  'Заголовок': s['Заголовок'] ?? '',
  'Главное': arr(s['Главное']),
  'Детали': arr(s['Детали']),
  'Инсайты': arr(s['Инсайты']),
  'Проблемы': arr(s['Проблемы']),
  'Следующие шаги': arr(s['Следующие шаги'])
};

// Дата записи в локальной таймзоне -> YYYY-MM-DD
const now = new Date();
const fmt = new Intl.DateTimeFormat('en-CA', {
  timeZone: TZ, year: 'numeric', month: '2-digit', day: '2-digit'
});
const date = fmt.format(now); // YYYY-MM-DD

// Транскрипт мог прийти от основного Whisper или от резервного Groq.
let transcript = '';
try { transcript = $('OpenAI Transcribe (Whisper)').item.json.text || ''; } catch (e) {}
if (!transcript) { try { transcript = $('Groq Transcribe (Fallback)').item.json.text || ''; } catch (e) {} }
const chatId = $('Telegram Trigger (Voice)').item.json.message.chat.id;

return {
  json: {
    token: 'REPLACE_SHARED_TOKEN', // должен совпадать с DIARY_TOKEN в Script Properties
    date,
    transcript,
    summary,
    chatId
  }
};

