// При ошибке Whisper не пробрасывает binary дальше. Берём аудио заново
// из Telegram Download Voice и нормализуем имя/расширение для Groq:
// голосовые Telegram приходят как .oga, а Groq принимает только
// [flac mp3 mp4 mpeg mpga m4a ogg opus wav webm].
const ALLOWED = ['flac','mp3','mp4','mpeg','mpga','m4a','ogg','opus','wav','webm'];
const src = $('Telegram Download Voice').first().binary;
if (!src || !src.data) {
  throw new Error('Не найден аудиофайл (binary data) из Telegram Download Voice для резервной расшифровки.');
}
const meta = src.data;
let ext = (meta.fileExtension || '').toLowerCase();
const mime = (meta.mimeType || '').toLowerCase();
if (!ALLOWED.includes(ext)) {
  if (mime.includes('ogg') || mime.includes('opus') || ext === 'oga') ext = 'ogg';
  else if (mime.includes('mpeg') || mime.includes('mp3')) ext = 'mp3';
  else if (mime.includes('mp4') || mime.includes('m4a') || mime.includes('aac')) ext = 'm4a';
  else if (mime.includes('wav')) ext = 'wav';
  else if (mime.includes('webm')) ext = 'webm';
  else ext = 'ogg';
}
const binary = { data: { ...meta, fileName: 'audio.' + ext, fileExtension: ext, mimeType: mime || 'audio/ogg' } };
return { json: $json, binary };

// Классифицируем ошибку и формируем понятное сообщение владельцу.
const err = $json.error || {};
const raw = '' + (err.message || err.description || (typeof $json.error === 'string' ? $json.error : '') || $json.message || '');
const step = err.node?.name || $json.node?.name || 'неизвестный';
const low = raw.toLowerCase();
const NL = String.fromCharCode(10);
let advice;
if (low.includes('insufficient_quota') || low.includes('exceeded your current quota') || low.includes('billing') || low.includes('payment')) {
  advice = '💳 Закончились средства или квота OpenAI. Пополните баланс в кабинете OpenAI (Settings → Billing) и убедитесь, что ключ из платного проекта.';
} else if (low.includes('429') || low.includes('rate limit') || low.includes('too many requests')) {
  advice = '⏳ Временный лимит запросов к ИИ. Это пройдёт само — отправьте запись ещё раз через минуту.';
} else {
  advice = 'Попробуйте ещё раз. Если повторяется — проверьте лог выполнения в n8n.';
}
let chatId;
try { chatId = $('Telegram Trigger (Voice)').first().json.message.chat.id; } catch (e) { chatId = $json.chatId; }
const errorMessage = ['❌ Не удалось сохранить запись дневника.', '', '*Шаг:* ' + step, '*Ошибка:* ' + (raw || 'неизвестная ошибка'), '', advice].join(NL);
return { json: { chatId, errorMessage } };
